<tr><td style="border:1px solid rgba(128,128,128,.3);padding:.4rem"><b>अरावली प्रदेश</b></td><td style="border:1px solid rgba(128,128,128,.3);padding:.4rem">≈9%</td><td style="border:1px solid rgba(128,128,128,.3);padding:.4rem">≈10%</td><td style="border:1px solid rgba(128,128,128,.3);padding:.4rem">प्राचीनतम वलित पर्वत</td></tr>
