<tr><td style="border:1px solid rgba(128,128,128,.3);padding:.4rem"><b>रेग</b></td><td style="border:1px solid rgba(128,128,128,.3);padding:.4rem">कंकरीला मरुस्थल</td><td style="border:1px solid rgba(128,128,128,.3);padding:.4rem">—</td></tr>
