<tr><td style="border:1px solid rgba(128,128,128,.3);padding:.4rem"><b>सिलीसेढ़</b></td><td style="border:1px solid rgba(128,128,128,.3);padding:.4rem">अलवर</td><td style="border:1px solid rgba(128,128,128,.3);padding:.4rem">विनयसिंह</td><td style="border:1px solid rgba(128,128,128,.3);padding:.4rem">"राजस्थान का नंदन कानन"</td></tr>
