<tr><td style="border:1px solid rgba(128,128,128,.3);padding:.4rem"><b>सिद्धमुख</b></td><td style="border:1px solid rgba(128,128,128,.3);padding:.4rem">हनुमानगढ़-चूरू</td><td style="border:1px solid rgba(128,128,128,.3);padding:.4rem">रावी-व्यास का जल</td></tr>
